class MicroWebSocket:
    def __init__(self, host='0.0.0.0', port=80):
        self.host = host
        self.port = port
        self.clients = []
        self.handler = self._default_handler
        self.server_sock = None
        self._running = False
        self.HANDSHAKE_RESPONSE = (
            b"HTTP/1.1 101 Switching Protocols\r\n"
            b"Upgrade: websocket\r\n"
            b"Connection: Upgrade\r\n"
            b"Sec-WebSocket-Accept: %s\r\n"
            b"\r\n"
        )

    def _hash_websocket_key(self, key):
        import ubinascii
        import hashlib
        GUID = b"258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
        hashed = hashlib.sha1(key.encode('utf-8') + GUID).digest()
        return ubinascii.b2a_base64(hashed).strip().decode('utf-8')

    def _read_websocket_frame(self, client_sock):
        try:
            # Read first byte (FIN, RSV1-3, OPCODE)
            header = client_sock.recv(2)
            if not header:
                return None, None # Connection closed

            fin = (header[0] & 0x80) >> 7
            opcode = header[0] & 0x0F
            
            if opcode == 0x08: # Connection close frame
                return None, None

            # Read second byte (MASK, PAYLOAD LEN)
            mask = (header[1] & 0x80) >> 7
            length = header[1] & 0x7F

            if length == 126:
                length = int.from_bytes(client_sock.recv(2), 'big')
            elif length == 127:
                length = int.from_bytes(client_sock.recv(8), 'big')

            if mask:
                masking_key = client_sock.recv(4)
            else:
                masking_key = None # Server should not receive unmasked frames from client

            payload = client_sock.recv(length)

            if mask and masking_key:
                decoded_payload = bytearray(length)
                for i in range(length):
                    decoded_payload[i] = payload[i] ^ masking_key[i % 4]
                return opcode, decoded_payload.decode('utf-8')
            else:
                return opcode, payload.decode('utf-8')

        except OSError as e:
            # Handle client disconnection or other socket errors
            if e.args[0] == 104 or e.args[0] == 113: # ECONNRESET or EHOSTUNREACH
                return None, None
            raise

    def _write_websocket_frame(self, client_sock, data, opcode=0x01):
        try:
            payload_bytes = data.encode('utf-8')
            length = len(payload_bytes)

            header = bytearray(2)
            header[0] = 0x80 | opcode # FIN=1, RSV=0, OPCODE

            if length < 126:
                header[1] = length
                client_sock.send(header)
            elif length < 65536:
                header[1] = 126
                client_sock.send(header)
                client_sock.send(length.to_bytes(2, 'big'))
            else:
                header[1] = 127
                client_sock.send(header)
                client_sock.send(length.to_bytes(8, 'big'))

            client_sock.send(payload_bytes)
        except OSError as e:
            # Handle client disconnection or other socket errors
            if e.args[0] == 104 or e.args[0] == 113: # ECONNRESET or EHOSTUNREACH
                pass
            else:
                raise

    def send(self, client, message):
        """Sends a message to a specific client."""
        self._write_websocket_frame(client, message)

    def broadcast(self, message):
        """Sends a message to all connected clients."""
        disconnected_clients = []
        for client_sock, _ in self.clients:
            try:
                self._write_websocket_frame(client_sock, message)
            except OSError as e:
                if e.args[0] == 104 or e.args[0] == 113: # ECONNRESET or EHOSTUNREACH
                    disconnected_clients.append((client_sock, _))
                else:
                    raise
        for client_sock, _ in disconnected_clients:
            self.clients.remove((client_sock, _))
            try:
                client_sock.close()
            except OSError:
                pass

    def _client_handler(self, client_sock, addr):
        print("Client connected from:", addr)
        try:
            # Perform WebSocket handshake
            header_lines = []
            while True:
                line = client_sock.readline()
                if not line or line == b'\r\n':
                    break
                header_lines.append(line.decode('utf-8').strip())
            
            sec_websocket_key = None
            for line in header_lines:
                if line.startswith("Sec-WebSocket-Key:"):
                    sec_websocket_key = line.split(": ")[1]
                    break
            
            if sec_websocket_key:
                hashed_key = self._hash_websocket_key(sec_websocket_key)
                response = self.HANDSHAKE_RESPONSE % hashed_key.encode('utf-8')
                client_sock.send(response)
            else:
                print("WebSocket key not found, closing connection.")
                client_sock.close()
                return

            self.clients.append((client_sock, addr))
            print("WebSocket connection established with", addr)

            while True:
                opcode, msg = self._read_websocket_frame(client_sock)
                if opcode is None: # Client disconnected or error
                    break
                if opcode == 0x01: # Text frame
                    print(f"Received from {addr}: {msg}")
                    # Call the user-defined message handler
                    self.handler(client_sock, msg)
                elif opcode == 0x09: # Ping frame
                    self._write_websocket_frame(client_sock, msg, opcode=0x0A) # Pong
                # Other opcodes (binary, continuation) are not explicitly handled in this example

        except OSError as e:
            if e.args[0] == 104 or e.args[0] == 113: # ECONNRESET or EHOSTUNREACH
                print(f"Client {addr} disconnected abruptly.")
            else:
                print(f"Error handling client {addr}: {e}")
        finally:
            print("Client disconnected:", addr)
            if (client_sock, addr) in self.clients:
                self.clients.remove((client_sock, addr))
            try:
                client_sock.close()
            except OSError:
                pass

    def _listen_for_connections(self):
        self.server_sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_sock.bind((self.host, self.port))
        self.server_sock.listen(5)
        self.server_sock.settimeout(1.0) # Set a timeout for accept to check _running flag
        print(f"WebSocket server listening on ws://{self.host}:{self.port}")

        while self._running:
            try:
                client_sock, addr = self.server_sock.accept()
                _thread.start_new_thread(self._client_handler, (client_sock, addr))
            except socket.timeout:
                pass # Timeout occurred, check _running flag
            except OSError as e:
                if self._running: # Only print error if server is still supposed to be running
                    print(f"Server accept error: {e}")
                break # Exit loop if server socket error

        self.server_sock.close()
        print("WebSocket server stopped.")

    def set_message_handler(self, handler_func):
        """Sets the function to handle incoming WebSocket messages."""
        self.handler = handler_func

    def _default_handler(self, client, message):
        print(f"Default handler received: {message}")
        try:
            command = json.loads(message)
            if "action" in command:
                response = {"status": "success", "action_received": command["action"]}
                self.send(client, json.dumps(response))
            else:
                self.send(client, json.dumps({"status": "error", "message": "Invalid command format"}))
        except ValueError:
            self.send(client, json.dumps({"status": "error", "message": "Invalid JSON"}))
        except Exception as e:
            self.send(client, json.dumps({"status": "error", "message": str(e)}))

    def start(self):
        """Starts the WebSocket server in a new thread."""
        if not self._running:
            self._running = True
            _thread.start_new_thread(self._listen_for_connections, ())

    def stop(self):
        """Stops the WebSocket server."""
        self._running = False
        # Give some time for the accept loop to finish
        time.sleep(1.1) 
        # Close all client sockets
        for client_sock, _ in list(self.clients):
            try:
                client_sock.close()
            except OSError:
                pass
        self.clients.clear()
        if self.server_sock:
            try:
                self.server_sock.close()
            except OSError:
                pass
        print("Stopping server...")


# --- Example Usage ---

def connect_wifi(ssid, password):
    sta_if = network.WLAN(network.STA_IF)
    if not sta_if.isconnected():
        print('Connecting to network...')
        sta_if.active(True)
        sta_if.connect(ssid, password)
        while not sta_if.isconnected():
            time.sleep(1)
    print('Network config:', sta_if.ifconfig())
    return sta_if.ifconfig()[0] # Return IP address

def custom_message_handler(client, message):
    """
    Custom handler for incoming WebSocket messages.
    This function will be called whenever a client sends a message.
    """
    try:
        command = json.loads(message)
        print(f"Handling command: {command}")

        action = command.get("action")
        device_id = command.get("device_id")

        if action == "turn_on":
            print(f"Device {device_id} turned ON!")
            response = {"status": "success", "device_id": device_id, "state": "on"}
            ws_server.send(client, json.dumps(response))
            ws_server.broadcast(json.dumps({"type": "update", "device_id": device_id, "state": "on"})) # Notify all clients
        elif action == "turn_off":
            print(f"Device {device_id} turned OFF!")
            response = {"status": "success", "device_id": device_id, "state": "off"}
            ws_server.send(client, json.dumps(response))
            ws_server.broadcast(json.dumps({"type": "update", "device_id": device_id, "state": "off"})) # Notify all clients
        elif action == "get_status":
            # Simulate device status
            status = {"device_id": device_id, "state": "unknown", "temperature": 25.5}
            response = {"status": "success", "data": status}
            ws_server.send(client, json.dumps(response))
        else:
            response = {"status": "error", "message": "Unknown action"}
            ws_server.send(client, json.dumps(response))

    except ValueError:
        response = {"status": "error", "message": "Invalid JSON format"}
        ws_server.send(client, json.dumps(response))
    except Exception as e:
        response = {"status": "error", "message": str(e)}
        ws_server.send(client, json.dumps(response))


